<?php function loadEnv($path){foreach(file($path)as $line){$line = trim($line);if($line === "" || $line[0]=== "#"){continue;}[$k, $v]= explode("=", $line, 2);putenv(trim($k). "=" . trim($v));}}loadEnv(__DIR__ . "/.env");$env = fn($k)=> getenv($k);$mysqli = new mysqli($env("DB_HOST"), $env("DB_USER"), $env("DB_PASS"), $env("DB_NAME"),);if($mysqli->connect_errno){http_response_code(500);die("DB connection failed");}function jsonOut($data, $code = 200){http_response_code($code);header("Content-Type: application/json");echo json_encode($data);exit();}function base64UrlDecode($s){return base64_decode(strtr($s, "-_", "+/"). str_repeat("=", 3 -((3 + strlen($s))% 4)),);}function currentUser($mysqli){$token = $_COOKIE["session_token"]?? null;if(!$token){return null;}$stmt = $mysqli->prepare("SELECT id, name, email, picture, session_expires FROM users WHERE session_token = ?",);$stmt->bind_param("s", $token);$stmt->execute();$user = $stmt->get_result()->fetch_assoc();if(!$user){return null;}if(strtotime($user["session_expires"])< time()){return null;}return $user;}header("Access-Control-Allow-Origin: http://localhost:3000");header("Access-Control-Allow-Credentials: true");header("Access-Control-Allow-Methods: GET, POST, OPTIONS");if($_SERVER["REQUEST_METHOD"]=== "OPTIONS"){exit();}$path = trim(parse_url($_SERVER["REQUEST_URI"], PHP_URL_PATH), "/");$action = $path === "" ? "home" : explode("/", $path)[0];switch($action){case "login": $params = http_build_query(["client_id" => $env("GOOGLE_CLIENT_ID"), "redirect_uri" => $env("REDIRECT_URI"), "response_type" => "code", "scope" => "openid email profile", "access_type" => "online", "prompt" => "select_account",]);header("Location: https://accounts.google.com/o/oauth2/v2/auth?" . $params,);exit();case "callback": $code = $_GET["code"]?? null;if(!$code){header("Location: http://localhost:3000/?error=login_cancelled");exit();}$ch = curl_init("https://oauth2.googleapis.com/token");curl_setopt_array($ch,[CURLOPT_POST => true, CURLOPT_R