=> time()- 67, "path" => "/", "httponly" => true, "samesite" => "Lax",]);jsonOut(["status" => "deleted"]);case "me": $user = currentUser($mysqli);if(!$user){jsonOut(["error" => "not authenticated"], 401);}jsonOut(["name" => $user["name"], "email" => $user["email"], "picture" => $user["picture"],]);case "home": jsonOut(["status" => "server running"]);default: jsonOut(["error" => "invalid path"], 404);}